class FinancialBusinessLogic:
    """Encapsulates all business logic for financial operations."""

    _tx_counter = 0

    @classmethod
    def _generate_transaction_id(cls):
        cls._tx_counter += 1
        return f"TXN{datetime.utcnow().strftime('%Y%m%d%H%M%S')}{cls._tx_counter:04d}"

    @staticmethod
    def get_balance(account_id):
        logger.info(f"Business logic: getBalance for account {account_id}")
        if account_id not in accounts_db:
            return BalanceResponse(
                account_id=account_id,
                balance=Decimal("0.00"),
                currency="USD",
                as_of=datetime.utcnow(),
                status_code=404,
                status_message=f"Account '{account_id}' not found.",
            )

        account = accounts_db[account_id]
        if not account["is_active"]:
            return BalanceResponse(
                account_id=account_id,
                balance=account["balance"],
                currency=account["currency"],
                as_of=datetime.utcnow(),
                status_code=403,
                status_message=f"Account '{account_id}' is inactive.",
            )

        return BalanceResponse(
            account_id=account_id,
            balance=account["balance"],
            currency=account["currency"],
            as_of=datetime.utcnow(),
            status_code=200,
            status_message="Success",
        )

    @classmethod
    def transfer_funds(cls, from_account_id, to_account_id, amount, currency, reference_note):
        logger.info(
            f"Business logic: transferFunds from {from_account_id} to {to_account_id}, amount={amount} {currency}"
        )

        # Validate accounts exist
        if from_account_id not in accounts_db:
            return TransferResponse(
                transaction_id="",
                from_account_id=from_account_id,
                to_account_id=to_account_id,
                amount=amount,
                currency=currency or "USD",
                timestamp=datetime.utcnow(),
                status_code=404,
                status_message=f"Source account '{from_account_id}' not found.",
                from_new_balance=Decimal("0.00"),
                to_new_balance=Decimal("0.00"),
            )

        if to_account_id not in accounts_db:
            return TransferResponse(
                transaction_id="",
                from_account_id=from_account_id,
                to_account_id=to_account_id,
                amount=amount,
                currency=currency or "USD",
                timestamp=datetime.utcnow(),
                status_code=404,
                status_message=f"Destination account '{to_account_id}' not found.",
                from_new_balance=Decimal("0.00"),
                to_new_balance=Decimal("0.00"),
            )

        from_account = accounts_db[from_account_id]
        to_account = accounts_db[to_account_id]

        # Validate accounts are active
        if not from_account["is_active"]:
            return TransferResponse(
                transaction_id="",
                from_account_id=from_account_id,
                to_account_id=to_account_id,
                amount=amount,
                currency=currency or "USD",
                timestamp=datetime.utcnow(),
                status_code=403,
                status_message=f"Source account '{from_account_id}' is inactive.",
                from_new_balance=from_account["balance"],
                to_new_balance=to_account["balance"],
            )

        if not to_account["is_active"]:
            return TransferResponse(
                transaction_id="",
                from_account_id=from_account_id,
                to_account_id=to_account_id,
                amount=amount,
                currency=currency or "USD",
                timestamp=datetime.utcnow(),
                status_code=403,
                status_message=f"Destination account '{to_account_id}' is inactive.",
                from_new_balance=from_account["balance"],
                to_new_balance=to_account["balance"],
            )

        # Validate amount
        if amount is None or amount <= 0:
            return TransferResponse(
                transaction_id="",
                from_account_id=from_account_id,
                to_account_id=to_account_id,
                amount=amount or Decimal("0.00"),
                currency=currency or "USD",
                timestamp=datetime.utcnow(),
                status_code=400,
                status_message="Transfer amount must be greater than zero.",
                from_new_balance=from_account["balance"],
                to_new_balance=to_account["balance"],
            )

        # Check sufficient funds
        if from_account["balance"] < amount:
            return TransferResponse(
                transaction_id="",
                from_account_id=from_account_id,
                to_account_id=to_account_id,
                amount=amount,
                currency=currency or "USD",
                timestamp=datetime.utcnow(),
                status_code=402,
                status_message=f"Insufficient funds. Available balance: {from_account['balance']} {from_account['currency']}",
                from_new_balance=from_account["balance"],
                to_new_balance=to_account["balance"],
            )

        # Same account check
        if from_account_id == to_account_id:
            return TransferResponse(
                transaction_id="",
                from_account_id=from_account_id,
                to_account_id=to_account_id,
                amount=amount,
                currency=currency or "USD",
                timestamp=datetime.utcnow(),
                status_code=400,
                status_message="Cannot transfer to the same account.",
                from_new_balance=from_account["balance"],
                to_new_balance=to_account["balance"],
            )

        # Execute transfer
        from_account["balance"] -= amount
        to_account["balance"] += amount

        transaction_id = cls._generate_transaction_id()
        now = datetime.utcnow()

        # Log transaction
        transaction_log.append({
            "transaction_id": transaction_id,
            "from_account_id": from_account_id,
            "to_account_id": to_account_id,
            "amount": amount,
            "currency": currency or "USD",
            "reference_note": reference_note or "",
            "timestamp": now,
        })

        logger.info(f"Transfer successful: {transaction_id}")

        return TransferResponse(
            transaction_id=transaction_id,
            from_account_id=from_account_id,
            to_account_id=to_account_id,
            amount=amount,
            currency=currency or "USD",
            timestamp=now,
            status_code=200,
            status_message="Transfer completed successfully.",
            from_new_balance=from_account["balance"],
            to_new_balance=to_account["balance"],
        )

