# --- SOAP Service Definition ---

class FinancialService(Service):
    """SOAP Service exposing financial operations with SOAPAction routing."""

    @rpc(
        Unicode(min_occurs=1),
        _returns=BalanceResponse,
        _soap_action="http://financial.services.api/getBalance",
        _in_variable_names={"account_id": "accountId"},
        _out_variable_name="GetBalanceResult",
    )
    def getBalance(ctx, account_id):
        """Retrieve the current balance for a given account."""
        logger.info(f"SOAP operation getBalance called with accountId={account_id}")
        return FinancialBusinessLogic.get_balance(account_id)

    @rpc(
        Unicode(min_occurs=1),
        Unicode(min_occurs=1),
        SpyneDecimal(min_occurs=1),
        Unicode,
        Unicode,
        _returns=TransferResponse,
        _soap_action="http://financial.services.api/transferFunds",
        _in_variable_names={
            "from_account_id": "fromAccountId",
            "to_account_id": "toAccountId",
            "amount": "amount",
            "currency": "currency",
            "reference_note": "referenceNote",
        },
        _out_variable_name="TransferFundsResult",
    )
    def transferFunds(ctx, from_account_id, to_account_id, amount, currency, reference_note):
        """Transfer funds between two accounts."""
        logger.info(
            f"SOAP operation transferFunds called: {from_account_id} -> {to_account_id}, amount={amount}"
        )
        return FinancialBusinessLogic.transfer_funds(
            from_account_id, to_account_id, amount, currency, reference_note
        )

    @rpc(
        Unicode(min_occurs=1),
        _returns=AccountInfo,
        _soap_action="http://financial.services.api/getAccountInfo",
        _in_variable_names={"account_id": "accountId"},
        _out_variable_name="GetAccountInfoResult",
    )
    def getAccountInfo(ctx, account_id):
        """Retrieve detailed account information."""
        logger.info(f"SOAP operation getAccountInfo called with accountId={account_id}")
        return FinancialBusinessLogic.get_account_info(account_id)

    @rpc(
        Unicode(min_occurs=1),
        _returns=TransactionHistoryResponse,
        _soap_action="http://financial.services.api/getTransactionHistory",
        _in_variable_names={"account_id": "accountId"},
        _out_variable_name="GetTransactionHistoryResult",
    )
    def getTransactionHistory(ctx, account_id):
        """Retrieve transaction history for a given account."""
        logger.info(f"SOAP operation getTransactionHistory called with accountId={account_id}")
        return FinancialBusinessLogic.get_transaction_history(account_id)

    @rpc(
        _returns=AccountListResponse,
        _soap_action="http://financial.services.api/listAllAccounts",
        _out_variable_name="ListAllAccountsResult",
    )
    def listAllAccounts(ctx):
        """List all accounts in the system."""
        logger.info("SOAP operation listAllAccounts called")
        return FinancialBusinessLogic.list_all_accounts()


# --- Application setup ---

def create_soap_application():
    """Create and configure the Spyne SOAP application."""
    app = Application(
        [FinancialService],
        tns="financial.services.api",
        in_protocol=Soap11(validator="lxml"),
        out_protocol=Soap11(),
    )
    return app


def create_wsgi_application():
    """Create the WSGI application wrapping the SOAP application."""
    soap_app = create_soap_application()
    wsgi_app = WsgiApplication(soap_app)
    return wsgi_app


